from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. The function groups information by subject and
    uses natural phrasing for known predicates, falling back to a generic style
    for unknown ones.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Mapping of predicates to phrasing functions
    def phrase(subject: str, predicate: str, obj: str, first: bool) -> str:
        """Return a natural phrase for a given predicate."""
        # Known predicates
        if predicate == "cityServed":
            return f"{subject} serves the city of {obj}"
        if predicate == "location":
            return f"{subject} is located in {obj}"
        if predicate == "country":
            return f"{subject} is in {obj}"
        if predicate == "isPartOf":
            return f"{subject} is part of {obj}"
        if predicate == "elevationAboveTheSeaLevel":
            return f"{subject} lies at an elevation of {obj} metres above sea level"
        if predicate == "elevationAboveTheSeaLevelInFeet":
            return f"{subject} lies at an elevation of {obj} feet above sea level"
        if predicate == "operatingOrganisation":
            return f"{subject} is operated by {obj}"
        if predicate == "runwaySurfaceType":
            return f"{subject} has a runway surface of {obj}"
        if predicate == "runwayName":
            return f"{subject}'s runway is named {obj}"
        if predicate == "runwayLength":
            return f"{subject}'s runway length is {obj}"
        if predicate.endswith("RunwayLengthFeet"):
            idx = predicate.split("Runway")[0]
            return f"{subject}'s {idx.lower()} runway is {obj} feet long"
        if predicate.endswith("RunwayLengthMetre"):
            idx = predicate.split("Runway")[0]
            return f"{subject}'s {idx.lower()} runway is {obj} metres long"
        # Fallback generic phrasing
        return f"{subject} has {predicate} {obj}"

    # Group triples by subject
    from collections import defaultdict
    grouped = defaultdict(list)
    for t in triples:
        grouped[t.subject].append(t)

    clauses: list[str] = []
    for subj, triples_list in grouped.items():
        # Build phrases for this subject
        subj_phrases = []
        for i, t in enumerate(triples_list):
            obj = _clean(t.object)
            phr = phrase(subj, t.predicate, obj, i == 0)
            subj_phrases.append(phr)
        # Combine phrases for the same subject
        if len(subj_phrases) == 1:
            clause = subj_phrases[0]
        else:
            # Use commas and a final "and"
            clause = ", ".join(subj_phrases[:-1]) + f", and {subj_phrases[-1]}"
        clauses.append(clause)

    # Combine all subject clauses into one complex sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = "; ".join(clauses) + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

